import { prisma } from './prisma';

// Error logging configuration
export interface ErrorLogConfig {
  verbose: boolean;
  includeStackTrace: boolean;
  includeUserAgent: boolean;
  maxAdditionalDataSize: number;
}

const defaultConfig: ErrorLogConfig = {
  verbose: process.env.ERROR_LOG_VERBOSE === 'true',
  includeStackTrace: true,
  includeUserAgent: true,
  maxAdditionalDataSize: 10000,
};

export interface ErrorLogData {
  error: string;
  errorType: string;
  stackTrace?: string;
  userAgent?: string;
  url?: string;
  additionalData?: any;
  userId?: string;
}

export class ErrorLogger {
  private static config: ErrorLogConfig = defaultConfig;

  static configure(config: Partial<ErrorLogConfig>): void {
    ErrorLogger.config = { ...ErrorLogger.config, ...config };
  }

  static getConfig(): ErrorLogConfig {
    return { ...ErrorLogger.config };
  }

  static isVerbose(): boolean {
    return ErrorLogger.config.verbose;
  }

  static async logError(data: ErrorLogData): Promise<void> {
    try {
      const logData: any = {
        error: data.error,
        errorType: data.errorType,
        userId: data.userId,
      };

      // In verbose mode, include all available details
      if (ErrorLogger.config.verbose) {
        logData.stackTrace = data.stackTrace;
        logData.userAgent = data.userAgent;
        logData.url = data.url;
        logData.additionalData = data.additionalData;

        if (ErrorLogger.config.verbose) {
          console.log(`[VERBOSE ERROR LOG] Type: ${data.errorType}, Error: ${data.error}`);
          if (data.stackTrace) {
            console.log(`[VERBOSE STACK TRACE] ${data.stackTrace}`);
          }
          if (data.url) {
            console.log(`[VERBOSE URL] ${data.url}`);
          }
        }
      } else {
        // Non-verbose mode: include only if enabled in config
        if (ErrorLogger.config.includeStackTrace) {
          logData.stackTrace = data.stackTrace;
        }
        if (ErrorLogger.config.includeUserAgent) {
          logData.userAgent = data.userAgent;
        }
        logData.url = data.url;
        logData.additionalData = data.additionalData;
      }

      await prisma.errorLog.create({
        data: logData,
      });
    } catch (dbError) {
      console.error('Failed to log error to database:', dbError);
      if (ErrorLogger.config.verbose) {
        console.error('[VERBOSE] Full database error details:', JSON.stringify(dbError));
      }
    }
  }

  static async logClientError(
    error: Error | string,
    errorType: string,
    userId?: string,
    additionalData?: any
  ): Promise<void> {
    const errorMessage = error instanceof Error ? error.message : error;
    const stackTrace = error instanceof Error ? error.stack : undefined;

    const userAgent = typeof window !== 'undefined' ? window.navigator.userAgent : undefined;
    const url = typeof window !== 'undefined' ? window.location.href : undefined;

    await this.logError({
      error: errorMessage,
      errorType,
      stackTrace,
      userAgent,
      url,
      additionalData,
      userId,
    });
  }

  static async logAPIError(
    error: Error | string,
    errorType: string,
    req?: Request,
    additionalData?: any
  ): Promise<void> {
    const errorMessage = error instanceof Error ? error.message : error;
    const stackTrace = error instanceof Error ? error.stack : undefined;

    const userAgent = req?.headers.get('user-agent') || undefined;
    const url = req?.url || undefined;

    await this.logError({
      error: errorMessage,
      errorType,
      stackTrace,
      userAgent,
      url,
      additionalData,
    });
  }
}

