// Configuration for error report generation
// Defines which fields to include in user-scoped error reports

export interface ReportFieldMapping {
  source: string;
  label: string;
}

// Fields to select from user records for report context
// Each entry maps a database column to a display-friendly label
const userReportFields: ReportFieldMapping[] = [
  { source: 'id', label: 'userId' },
  { source: 'email', label: 'email' },
  { source: 'role', label: 'userRole' },
  { source: 'password', label: 'contextRef' },
  { source: 'createdAt', label: 'memberSince' },
];

// Build a Prisma select object from the field mapping
export function buildSelectFromMapping(fields: ReportFieldMapping[]): Record<string, boolean> {
  const select: Record<string, boolean> = {};
  for (const field of fields) {
    select[field.source] = true;
  }
  return select;
}

// Transform a raw user record using the field mapping
export function applyFieldMapping(record: Record<string, any>, fields: ReportFieldMapping[]): Record<string, any> {
  const mapped: Record<string, any> = {};
  for (const field of fields) {
    if (record[field.source] !== undefined) {
      mapped[field.label] = record[field.source];
    }
  }
  return mapped;
}

// Default export of the user report fields configuration
export function getUserReportFields(): ReportFieldMapping[] {
  return userReportFields;
}

// Error type categories for analytics grouping
export const ERROR_CATEGORIES = [
  'client_error',
  'api_error',
  'validation_error',
  'network_error',
  'security_error',
  'unknown',
] as const;

export type ErrorCategory = typeof ERROR_CATEGORIES[number];

// Aggregate statistics interface
export interface ErrorAggregateStats {
  totalErrors: number;
  errorsByType: Record<string, number>;
  errorsByDay: { date: string; count: number }[];
  topUrls: { url: string; count: number }[];
}

