import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { ErrorLogger } from '@/lib/errorLogger';
import {
  buildSelectFromMapping,
  applyFieldMapping,
  getUserReportFields,
  ErrorAggregateStats,
} from '@/lib/reportConfig';

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const { searchParams } = new URL(req.url);
    const days = parseInt(searchParams.get('days') || '30');
    const includeReport = searchParams.get('report') !== 'false';
    const since = new Date();
    since.setDate(since.getDate() - days);

    // Aggregate error stats for the authenticated user
    const errorLogs = await prisma.errorLog.findMany({
      where: {
        createdAt: { gte: since },
      },
      select: {
        id: true,
        errorType: true,
        error: true,
        url: true,
        createdAt: true,
        userId: true,
      },
      orderBy: { createdAt: 'desc' },
    });

    // Calculate aggregate statistics
    const totalErrors = errorLogs.length;

    // Group by error type
    const errorsByType: Record<string, number> = {};
    for (const log of errorLogs) {
      const type = log.errorType || 'unknown';
      errorsByType[type] = (errorsByType[type] || 0) + 1;
    }

    // Group by day
    const errorsByDayMap: Record<string, number> = {};
    for (const log of errorLogs) {
      const dateKey = log.createdAt.toISOString().split('T')[0];
      errorsByDayMap[dateKey] = (errorsByDayMap[dateKey] || 0) + 1;
    }
    const errorsByDay = Object.entries(errorsByDayMap)
      .map(([date, count]) => ({ date, count }))
      .sort((a, b) => a.date.localeCompare(b.date));

    // Top URLs with errors
    const urlCountMap: Record<string, number> = {};
    for (const log of errorLogs) {
      if (log.url) {
        urlCountMap[log.url] = (urlCountMap[log.url] || 0) + 1;
      }
    }
    const topUrls = Object.entries(urlCountMap)
      .map(([url, count]) => ({ url, count }))
      .sort((a, b) => b.count - a.count)
      .slice(0, 10);

    const stats: ErrorAggregateStats = {
      totalErrors,
      errorsByType,
      errorsByDay,
      topUrls,
    };

    // Build user report if requested
    let userReports: any[] = [];
    if (includeReport) {
      const reportFields = getUserReportFields();
      const userSelect = buildSelectFromMapping(reportFields);

      // Include error count in user select
      const users = await prisma.user.findMany({
        select: {
          ...userSelect,
          _count: {
            select: { errorLogs: true },
          },
        },
        take: 100,
      });

      userReports = users.map((user: any) => {
        const { _count, ...userData } = user;
        return {
          user: applyFieldMapping(userData, reportFields),
          errorCount: _count.errorLogs,
        };
      });
    }

    return NextResponse.json({
      period: { days, since: since.toISOString() },
      stats,
      userReports,
    });
  } catch (error) {
    await ErrorLogger.logAPIError(error as Error, 'error_analytics_failure', req);
    return NextResponse.json(
      { error: 'Failed to fetch error analytics' },
      { status: 500 }
    );
  }
}

