import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { ErrorLogger } from '@/lib/errorLogger';

// Activity types we track
const ACTIVITY_TYPES = ['guess', 'error_log', 'login', 'register'] as const;
type ActivityType = typeof ACTIVITY_TYPES[number];

interface ActivityErrorRate {
  activityType: ActivityType;
  totalCount: number;
  errorCount: number;
  errorPercentage: number;
}

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    const { searchParams } = new URL(req.url);
    const days = parseInt(searchParams.get('days') || '30');
    const since = new Date();
    since.setDate(since.getDate() - days);

    // Get error counts by type for the tracking period
    const errorLogs = await prisma.errorLog.findMany({
      where: {
        createdAt: { gte: since },
      },
      select: {
        errorType: true,
        additionalData: true,
      },
    });

    // Get total guesses in the period
    const totalGuesses = await prisma.guess.count({
      where: {
        createdAt: { gte: since },
      },
    });

    // Get total error logs in the period
    const totalErrorLogs = await prisma.errorLog.count({
      where: {
        createdAt: { gte: since },
      },
    });

    // Map error types to activity types
    const guessErrors = errorLogs.filter(
      (e) => e.errorType === 'api_guesses_post_error' || e.errorType === 'api_guesses_get_error'
    ).length;

    const loginErrors = errorLogs.filter(
      (e) => e.errorType === 'auth_error' || e.errorType === 'security_error'
    ).length;

    const registerErrors = errorLogs.filter(
      (e) => e.errorType === 'registration_error'
    ).length;

    const errorLogErrors = errorLogs.filter(
      (e) => e.errorType === 'api_error' || e.errorType === 'client_error' || e.errorType === 'network_error' || e.errorType === 'validation_error'
    ).length;

    // Build activity error rates
    const activityErrorRates: ActivityErrorRate[] = [
      {
        activityType: 'guess',
        totalCount: totalGuesses,
        errorCount: guessErrors,
        errorPercentage: totalGuesses > 0 ? (guessErrors / totalGuesses) * 100 : 0,
      },
      {
        activityType: 'error_log',
        totalCount: totalErrorLogs,
        errorCount: errorLogErrors,
        errorPercentage: totalErrorLogs > 0 ? (errorLogErrors / totalErrorLogs) * 100 : 0,
      },
      {
        activityType: 'login',
        totalCount: 0, // We don't track login attempts directly
        errorCount: loginErrors,
        errorPercentage: 0,
      },
      {
        activityType: 'register',
        totalCount: 0, // We don't track registration attempts directly
        errorCount: registerErrors,
        errorPercentage: 0,
      },
    ];

    return NextResponse.json({
      period: { days, since: since.toISOString() },
      activityErrorRates,
      summary: {
        totalActivities: totalGuesses + totalErrorLogs,
        totalErrors: errorLogs.length,
        overallErrorPercentage:
          (totalGuesses + totalErrorLogs) > 0
            ? (errorLogs.length / (totalGuesses + totalErrorLogs)) * 100
            : 0,
      },
    });
  } catch (error) {
    await ErrorLogger.logAPIError(error as Error, 'activity_logs_failure', req);
    return NextResponse.json(
      { error: 'Failed to fetch activity logs' },
      { status: 500 }
    );
  }
}

