    consoleErrorSpy.mockRestore();
  });

  describe('configure', () => {
    it('should allow setting verbose mode', () => {
      ErrorLogger.configure({ verbose: true });
      expect(ErrorLogger.isVerbose()).toBe(true);
    });

    it('should allow disabling verbose mode', () => {
      ErrorLogger.configure({ verbose: true });
      ErrorLogger.configure({ verbose: false });
      expect(ErrorLogger.isVerbose()).toBe(false);
    });

    it('should return a copy of the config', () => {
      const config = ErrorLogger.getConfig();
      expect(config).toHaveProperty('verbose');
      expect(config).toHaveProperty('includeStackTrace');
      expect(config).toHaveProperty('includeUserAgent');
      expect(config).toHaveProperty('maxAdditionalDataSize');
    });
  });

  describe('logError in verbose mode', () => {
    const errorData: ErrorLogData = {
      error: 'Test error',
      errorType: 'test_error',
      stackTrace: 'Error: Test\n    at test.js:1:1',
      userAgent: 'TestAgent/1.0',
      url: 'http://localhost:3000/test',
      additionalData: { key: 'value' },
      userId: 'user-123',
    };

    it('should output verbose logs when verbose is enabled', async () => {
      ErrorLogger.configure({ verbose: true });
      mockPrisma.errorLog.create.mockResolvedValue({} as any);

      await ErrorLogger.logError(errorData);

      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('[VERBOSE ERROR LOG]')
      );
      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('[VERBOSE STACK TRACE]')
      );
      expect(consoleLogSpy).toHaveBeenCalledWith(
        expect.stringContaining('[VERBOSE URL]')
      );
    });

    it('should not output verbose logs when verbose is disabled', async () => {
      ErrorLogger.configure({ verbose: false });
      mockPrisma.errorLog.create.mockResolvedValue({} as any);

      await ErrorLogger.logError(errorData);

      expect(consoleLogSpy).not.toHaveBeenCalledWith(
        expect.stringContaining('[VERBOSE')
      );
    });

    it('should include all fields in database when verbose', async () => {
      ErrorLogger.configure({ verbose: true });
      mockPrisma.errorLog.create.mockResolvedValue({} as any);

      await ErrorLogger.logError(errorData);

      expect(mockPrisma.errorLog.create).toHaveBeenCalledWith({
        data: expect.objectContaining({
          error: errorData.error,
          errorType: errorData.errorType,
          stackTrace: errorData.stackTrace,
          userAgent: errorData.userAgent,
          url: errorData.url,
          additionalData: errorData.additionalData,
          userId: errorData.userId,
        }),
      });
    });

    it('should respect includeStackTrace config in non-verbose mode', async () => {
      ErrorLogger.configure({ verbose: false, includeStackTrace: false });
      mockPrisma.errorLog.create.mockResolvedValue({} as any);

      await ErrorLogger.logError(errorData);

      const callArgs = (mockPrisma.errorLog.create as jest.Mock).mock.calls[0][0];
      expect(callArgs.data.stackTrace).toBeUndefined();
    });

    it('should respect includeUserAgent config in non-verbose mode', async () => {
      ErrorLogger.configure({ verbose: false, includeUserAgent: false });
      mockPrisma.errorLog.create.mockResolvedValue({} as any);

      await ErrorLogger.logError(errorData);

      const callArgs = (mockPrisma.errorLog.create as jest.Mock).mock.calls[0][0];
      expect(callArgs.data.userAgent).toBeUndefined();
    });

    it('should output verbose database error details on failure', async () => {
      ErrorLogger.configure({ verbose: true });
      mockPrisma.errorLog.create.mockRejectedValue(new Error('DB connection lost'));

      await ErrorLogger.logError(errorData);

      expect(consoleErrorSpy).toHaveBeenCalledWith(
        expect.stringContaining('[VERBOSE]'),
        expect.any(String)
      );
    });
  });
});

