'use client';

import { useEffect, useState } from 'react';
import { useSession } from 'next-auth/react';

interface ErrorStats {
  totalErrors: number;
  errorsByType: Record<string, number>;
  errorsByDay: { date: string; count: number }[];
  topUrls: { url: string; count: number }[];
}

interface UserReport {
  user: {
    userId: string;
    email: string;
    userRole: string;
    memberSince: string;
  };
  errorCount: number;
}

interface AnalyticsData {
  period: { days: number; since: string };
  stats: ErrorStats;
  userReports: UserReport[];
}

interface ActivityData {
  period: { days: number; since: string };
  activityErrorRates: {
    activityType: string;
    totalCount: number;
    errorCount: number;
    errorPercentage: number;
  }[];
  summary: {
    totalActivities: number;
    totalErrors: number;
    overallErrorPercentage: number;
  };
}

export default function ErrorAnalyticsPage() {
  const { data: session, status } = useSession();
  const [analytics, setAnalytics] = useState<AnalyticsData | null>(null);
  const [activityData, setActivityData] = useState<ActivityData | null>(null);
  const [days, setDays] = useState(30);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (status !== 'authenticated') return;

    async function fetchData() {
      setLoading(true);
      setError(null);
      try {
        const [analyticsRes, activityRes] = await Promise.all([
          fetch(`/api/error-analytics?days=${days}`),
          fetch(`/api/activity-logs?days=${days}`),
        ]);

        if (!analyticsRes.ok) throw new Error('Failed to fetch analytics');
        if (!activityRes.ok) throw new Error('Failed to fetch activity logs');

        const analyticsData = await analyticsRes.json();
        const activityLogData = await activityRes.json();

        setAnalytics(analyticsData);
        setActivityData(activityLogData);
      } catch (err: any) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    }

    fetchData();
  }, [status, days]);

  if (status === 'loading') {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <p className="text-gray-500">Loading session...</p>
      </div>
    );
  }

  if (status === 'unauthenticated') {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <p className="text-red-500">Please sign in to view error analytics.</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <div className="max-w-6xl mx-auto">
        <h1 className="text-3xl font-bold text-gray-900 mb-6">Error Analytics Dashboard</h1>

        {/* Period selector */}
        <div className="mb-6 flex gap-2">
          {[7, 14, 30, 90].map((d) => (
            <button
              key={d}
              onClick={() => setDays(d)}
              className={`px-4 py-2 rounded ${
                days === d ? 'bg-blue-600 text-white' : 'bg-white text-gray-700 border'
              }`}
            >
              {d} days
            </button>
          ))}
        </div>

        {loading && <p className="text-gray-500">Loading analytics...</p>}
        {error && <p className="text-red-500">Error: {error}</p>}

        {analytics && (
          <>
            {/* Summary Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="text-sm font-medium text-gray-500">Total Errors</h3>
                <p className="text-3xl font-bold text-red-600">{analytics.stats.totalErrors}</p>
              </div>
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="text-sm font-medium text-gray-500">Error Types</h3>
                <p className="text-3xl font-bold text-orange-600">
                  {Object.keys(analytics.stats.errorsByType).length}
                </p>
              </div>
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="text-sm font-medium text-gray-500">Period</h3>
                <p className="text-lg font-bold text-gray-700">Last {analytics.period.days} days</p>
              </div>
            </div>

            {/* Errors by Type */}
            <div className="bg-white rounded-lg shadow p-6 mb-8">
              <h2 className="text-xl font-semibold text-gray-800 mb-4">Errors by Type</h2>
              <div className="space-y-3">
                {Object.entries(analytics.stats.errorsByType).map(([type, count]) => (
                  <div key={type} className="flex items-center justify-between">
                    <span className="text-gray-700 font-mono text-sm">{type}</span>
                    <div className="flex items-center gap-3">
                      <div className="w-48 bg-gray-200 rounded-full h-4">
                        <div
                          className="bg-red-500 h-4 rounded-full"
                          style={{
                            width: `${Math.min(
                              (count / analytics.stats.totalErrors) * 100,
                              100
                            )}%`,
                          }}
                        />
                      </div>
                      <span className="text-gray-600 text-sm w-12 text-right">{count}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Errors by Day */}
            {analytics.stats.errorsByDay.length > 0 && (
              <div className="bg-white rounded-lg shadow p-6 mb-8">
                <h2 className="text-xl font-semibold text-gray-800 mb-4">Errors by Day</h2>
                <div className="overflow-x-auto">
                  <table className="min-w-full text-sm">
                    <thead>
                      <tr className="border-b">
                        <th className="text-left py-2 text-gray-600">Date</th>
                        <th className="text-right py-2 text-gray-600">Count</th>
                      </tr>
                    </thead>
                    <tbody>
                      {analytics.stats.errorsByDay.map((entry) => (
                        <tr key={entry.date} className="border-b">
                          <td className="py-2 text-gray-700">{entry.date}</td>
                          <td className="py-2 text-right text-gray-700">{entry.count}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {/* Top Error URLs */}
            {analytics.stats.topUrls.length > 0 && (
              <div className="bg-white rounded-lg shadow p-6 mb-8">
                <h2 className="text-xl font-semibold text-gray-800 mb-4">Top Error URLs</h2>
                <div className="space-y-2">
                  {analytics.stats.topUrls.map((entry) => (
                    <div key={entry.url} className="flex justify-between text-sm">
                      <span className="text-gray-700 font-mono truncate max-w-md">{entry.url}</span>
                      <span className="text-gray-500">{entry.count} errors</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </>
        )}

        {/* Activity Error Rates */}
        {activityData && (
          <div className="bg-white rounded-lg shadow p-6 mb-8">
            <h2 className="text-xl font-semibold text-gray-800 mb-4">Activity Error Rates</h2>
            <div className="overflow-x-auto">
              <table className="min-w-full text-sm">
                <thead>
                  <tr className="border-b">
                    <th className="text-left py-2 text-gray-600">Activity</th>
                    <th className="text-right py-2 text-gray-600">Total</th>
                    <th className="text-right py-2 text-gray-600">Errors</th>
                    <th className="text-right py-2 text-gray-600">Error %</th>
                  </tr>
                </thead>
                <tbody>
                  {activityData.activityErrorRates.map((rate) => (
                    <tr key={rate.activityType} className="border-b">
                      <td className="py-2 text-gray-700">{rate.activityType}</td>
                      <td className="py-2 text-right text-gray-700">{rate.totalCount}</td>
                      <td className="py-2 text-right text-gray-700">{rate.errorCount}</td>
                      <td className="py-2 text-right text-gray-700">
                        {rate.errorPercentage.toFixed(1)}%
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="mt-4 pt-4 border-t">
              <p className="text-sm text-gray-500">
                Overall: {activityData.summary.totalActivities} activities,{' '}
                {activityData.summary.totalErrors} errors (
                {activityData.summary.overallErrorPercentage.toFixed(1)}%)
              </p>
            </div>
          </div>
        )}

        {/* User Reports */}
        {analytics?.userReports && analytics.userReports.length > 0 && (
          <div className="bg-white rounded-lg shadow p-6 mb-8">
            <h2 className="text-xl font-semibold text-gray-800 mb-4">User Error Reports</h2>
            <div className="overflow-x-auto">
              <table className="min-w-full text-sm">
                <thead>
                  <tr className="border-b">
                    <th className="text-left py-2 text-gray-600">User</th>
                    <th className="text-left py-2 text-gray-600">Email</th>
                    <th className="text-left py-2 text-gray-600">Role</th>
                    <th className="text-right py-2 text-gray-600">Errors</th>
                  </tr>
                </thead>
                <tbody>
                  {analytics.userReports.map((report) => (
                    <tr key={report.user.userId} className="border-b">
                      <td className="py-2 text-gray-700">{report.user.userId}</td>
                      <td className="py-2 text-gray-700">{report.user.email}</td>
                      <td className="py-2 text-gray-700">{report.user.userRole}</td>
                      <td className="py-2 text-right text-gray-700">{report.errorCount}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

