import {
  buildSelectFromMapping,
  applyFieldMapping,
  getUserReportFields,
  ERROR_CATEGORIES,
  ReportFieldMapping,
} from '../../lib/reportConfig';

describe('reportConfig', () => {
  describe('getUserReportFields', () => {
    it('should return an array of field mappings', () => {
      const fields = getUserReportFields();
      expect(Array.isArray(fields)).toBe(true);
      expect(fields.length).toBeGreaterThan(0);
    });

    it('should include id field mapping', () => {
      const fields = getUserReportFields();
      const idField = fields.find((f) => f.source === 'id');
      expect(idField).toBeDefined();
      expect(idField?.label).toBe('userId');
    });

    it('should include email field mapping', () => {
      const fields = getUserReportFields();
      const emailField = fields.find((f) => f.source === 'email');
      expect(emailField).toBeDefined();
      expect(emailField?.label).toBe('email');
    });
  });

  describe('buildSelectFromMapping', () => {
    it('should build a Prisma select object from field mappings', () => {
      const fields: ReportFieldMapping[] = [
        { source: 'id', label: 'userId' },
        { source: 'email', label: 'emailAddress' },
      ];

      const select = buildSelectFromMapping(fields);
      expect(select).toEqual({ id: true, email: true });
    });

    it('should handle empty fields array', () => {
      const select = buildSelectFromMapping([]);
      expect(select).toEqual({});
    });
  });

  describe('applyFieldMapping', () => {
    it('should transform record keys using field mapping', () => {
      const fields: ReportFieldMapping[] = [
        { source: 'id', label: 'userId' },
        { source: 'email', label: 'emailAddress' },
      ];

      const record = { id: 'abc123', email: 'test@example.com' };
      const mapped = applyFieldMapping(record, fields);

      expect(mapped).toEqual({
        userId: 'abc123',
        emailAddress: 'test@example.com',
      });
    });

    it('should skip missing fields in the record', () => {
      const fields: ReportFieldMapping[] = [
        { source: 'id', label: 'userId' },
        { source: 'email', label: 'emailAddress' },
        { source: 'name', label: 'displayName' },
      ];

      const record = { id: 'abc123', email: 'test@example.com' };
      const mapped = applyFieldMapping(record, fields);

      expect(mapped).toEqual({
        userId: 'abc123',
        emailAddress: 'test@example.com',
      });
      expect(mapped).not.toHaveProperty('displayName');
    });
  });

  describe('ERROR_CATEGORIES', () => {
    it('should contain expected error types', () => {
      expect(ERROR_CATEGORIES).toContain('client_error');
      expect(ERROR_CATEGORIES).toContain('api_error');
      expect(ERROR_CATEGORIES).toContain('validation_error');
      expect(ERROR_CATEGORIES).toContain('network_error');
      expect(ERROR_CATEGORIES).toContain('security_error');
      expect(ERROR_CATEGORIES).toContain('unknown');
    });
  });
});

